**2. 添加验证测试脚本**

建议在项目根目录创建 `test-error-handling.js`：

```javascript
// test-error-handling.js
const { spawn } = require('child_process');
const path = require('path');

function testUnhandledRejection() {
  return new Promise((resolve, reject) => {
    const proc = spawn('node', [path.join(__dirname, 'cli.js'), 'invalid_command'], {
      stdio: ['pipe', 'pipe', 'pipe']
    });

    let stderr = '';
    proc.stderr.on('data', (data) => { stderr += data.toString(); });
    proc.on('close', (code) => {
      if (code === 1 && stderr.includes('\x1b[31m')) {
        resolve('PASS');
      } else {
        reject(new Error(`Expected exit code 1 and red error marker. Got code=${code}, stderr=${stderr}`));
      }
    });
  });
}
```

